frappe.ui.form.on('Employee Assignment', {
    refresh: function(frm) {
        // تفعيل الفلتر عند تحميل الصفحة
        frm.set_query('project_site', function() {
            return {
                filters: {
                    'project': frm.doc.project
                }
            };
        });
    },

    project: function(frm) {
        // عند تغيير المشروع، يفرغ حقل الموقع القديم ويعيد الفلترة
        frm.set_value('project_site', '');
        frm.set_query('project_site', function() {
            return {
                filters: {
                    'project': frm.doc.project
                }
            };
        });
    }
});

frappe.ui.form.on('Employee', {
    validate: function(frm) {
        
        // 
        if (frm.doc.custom_national_id_number) {
            if (!/^1[0-9]{9}$/.test(frm.doc.custom_national_id_number)) {
                frappe.msgprint(__('عفواً، يجب أن تتكون الهوية الوطنية من 10 أرقام فقط وتبدأ برقم 1.'));
                frappe.validated = false;
            }
        }
        
        //
        if (frm.doc.custom_iqama_number) {
            if (!/^2[0-9]{9}$/.test(frm.doc.custom_iqama_number)) {
                frappe.msgprint(__('عفواً، يجب أن يتكون رقم الإقامة من 10 أرقام فقط ويبدأ برقم 2.'));
                frappe.validated = false;
            }
        }

        //
        if (frm.doc.custom_border_number) {
            if (!/^[34][0-9]{9}$/.test(frm.doc.custom_border_number)) {
                frappe.msgprint(__('عفواً، يجب أن يتكون رقم الحدود من 10 أرقام ويبدأ برقم 3 أو 4.'));
                frappe.validated = false;
            }
        }

        // 
        if (frm.doc.custom_gcc_id_card) {
            if (!/^[0-9]{8,15}$/.test(frm.doc.custom_gcc_id_card)) {
                frappe.msgprint(__('عفواً، رقم الهوية الخليجية يجب أن يتكون من 8 إلى 15 رقماً.'));
                frappe.validated = false;
            }
        }

        // 
        if (frm.doc.custom_saudi_mother_id) {
            if (!/^1[0-9]{9}$/.test(frm.doc.custom_saudi_mother_id)) {
                frappe.msgprint(__('عفواً، هوية الأم السعودية يجب أن تتكون من 10 أرقام وتبدأ برقم 1.'));
                frappe.validated = false;
            }
        }
        
    }
});

frappe.ui.form.on('Employee', {
    refresh: function(frm) {
        apply_designation_filter(frm);
    },
    grade: function(frm) {
        frm.set_value('designation', ''); // تفريغ المسمى عند تغيير الدرجة
        apply_designation_filter(frm);
    }
});

function apply_designation_filter(frm) {
    if (!frm.doc.grade) {
        // إذا لم يتم اختيار درجة، افتح القائمة بالكامل (أو اتركها كما هي)
        frm.set_query("designation", function() {
            return {};
        });
        return;
    }

    frappe.db.get_doc('Employee Grade', frm.doc.grade)
        .then(grade_doc => {
            
            // سحب البيانات من الجدول الفرعي
            let child_table_data = grade_doc.custom_allowed_designations || grade_doc.allowed_designations || grade_doc.designations;

            if (child_table_data && child_table_data.length > 0) {
                // استخراج المسميات
                let valid_designations = child_table_data.map(row => row.designation);
                
                // تطبيق الفلتر بصمت
                frm.set_query("designation", function() {
                    return {
                        filters: [
                            ["name", "in", valid_designations]
                        ]
                    };
                });
            } else {
                // إذا لم يجد مسميات للدرجة، يغلق القائمة
                frm.set_query("designation", function() {
                    return {
                        filters: [
                            ["name", "in", ["لا توجد وظائف"]] 
                        ]
                    };
                });
            }
        });
}

frappe.ui.form.on('Asset', {

    custom__last_maintenance_date: function(frm) {
        calculate_next_date(frm);
    },

    custom_maintenance_interval: function(frm) {
        calculate_next_date(frm);
    },

    custom_maintenance_frequency_type: function(frm) {
        calculate_next_date(frm);
    }

});

function calculate_next_date(frm) {

    if (!frm.doc.custom__last_maintenance_date || 
        !frm.doc.custom_maintenance_interval || 
        !frm.doc.custom_maintenance_frequency_type) {
        return;
    }

    let last_date = frappe.datetime.str_to_obj(frm.doc.custom__last_maintenance_date);
    let interval = parseInt(frm.doc.custom_maintenance_interval);
    let frequency = frm.doc.custom_maintenance_frequency_type;

    if (frequency === "Daily") {
        last_date.setDate(last_date.getDate() + interval);
    }

    if (frequency === "Weekly") {
        last_date.setDate(last_date.getDate() + (7 * interval));
    }

    if (frequency === "Monthly") {
        last_date.setMonth(last_date.getMonth() + interval);
    }

    if (frequency === "Yearly") {
        last_date.setFullYear(last_date.getFullYear() + interval);
    }

    frm.set_value("custom__next_maintenance_date",
        frappe.datetime.obj_to_str(last_date)
    );
}

frappe.ui.form.on('Project', {

    // =====================================================
    // 1️⃣ SETUP
    // -----------------------------------------------------
    // Purpose:
    // Automatically fetch "site_name" and "address"
    // from the linked "Project Site" when "site" is selected.

    // =====================================================
    setup: function(frm) {
        frm.add_fetch('site', 'site_name', 'site_name');
        frm.add_fetch('site', 'address', 'address');
        //  frm.add_fetch('site', 'city', 'city');
        // frm.add_fetch('site', 'administrative_region', 'administrative_region');
        

    },



    // =====================================================
    // 2️⃣ ONLOAD – Prevent duplicate Site selection
    // -----------------------------------------------------
    // Purpose:
    // Prevent users from selecting a Site that is already
    // added inside the custom_sites child table.

    onload: function(frm) {

        if (!frm.fields_dict.custom_sites) return;

        frm.fields_dict['custom_sites']
            .grid
            .get_field('site')
            .get_query = function(doc) {

                let selected_sites = (doc.custom_sites || [])
                    .map(row => row.site)
                    .filter(site => site);

                // If no sites selected yet → no filter needed
                if (!selected_sites.length) {
                    return {};
                }

                return {
                    filters: [
                        ["Project Site", "name", "not in", selected_sites]
                    ]
                };
            };
    },



    // =====================================================
    // 3️⃣ REFRESH – Rename "Add Row" button
    // -----------------------------------------------------
    // Purpose:
    // Change default button text to "Add Site"
    
    refresh: function(frm) {

        if (!frm.fields_dict.custom_sites) return;

        frm.fields_dict.custom_sites.grid.wrapper
            .find('.grid-add-row')
            .text('Add Site');
    },



    // =====================================================
    // 4️⃣ VALIDATE – Final duplicate protection
    // -----------------------------------------------------
    // Purpose:
    // Prevent saving the document if duplicate
    // Sites exist in child table.
    
    validate: function(frm) {

        let sites = new Set();

        (frm.doc.custom_sites || []).forEach(row => {

            if (!row.site) return;

            if (sites.has(row.site)) {
                frappe.throw(
                    __('This site is already added to this project!')
                );
            }

            sites.add(row.site);
        });
    }

});

frappe.ui.form.on("Employee Project Assignment", {

    // =====================================================
    // SETUP
    // =====================================================
    setup: function(frm) {

        frm._project_sites = [];

        // Filter Site based on selected Project
        frm.set_query("custom_site", function() {
            if (!frm._project_sites || !frm._project_sites.length) {
                return { filters: { name: ["=", ""] } };
            }
            return {
                filters: {
                    name: ["in", frm._project_sites]
                }
            };
        });

        // Prevent duplicate employees in child table
        frm.fields_dict.employee_table.grid
            .get_field("employee").get_query = function(doc) {
                const selected = (frm.doc.employee_table || [])
                    .map(r => r.employee)
                    .filter(Boolean);
                return {
                    filters: [["name", "not in", selected]]
                };
            };
    },

    // =====================================================
    // ONLOAD
    // =====================================================
    onload: function(frm) {
        frm.set_df_property("custom_site", "hidden", 0);
        frm.fields_dict.custom_site.$wrapper
            .find('input, .link-btn')
            .prop('disabled', true);
    },

    // =====================================================
    // REFRESH (Prevent 4-digit input)
    // =====================================================
    refresh: function(frm) {
        const field = frm.fields_dict.quantity;
        if (field && field.$input) {
            field.$input.off("input.quantity_limit");
            field.$input.attr("maxlength", 3);
            field.$input.on("input.quantity_limit", function() {
                let value = $(this).val();
                value = value.replace(/\D/g, "");
                if (value.length > 3) {
                    value = value.substring(0, 3);
                }
                $(this).val(value);
            });
        }
    },

    // =====================================================
    // PROJECT CHANGE → FILTER SITES
    // =====================================================
    custom_project: function(frm) {
        const site_input = frm.fields_dict.custom_site.$wrapper
            .find('input, .link-btn');

        frm.set_value("custom_site", null);
        frm._project_sites = [];

        if (!frm.doc.custom_project) {
            site_input.prop('disabled', true);
            return;
        }

        site_input.prop('disabled', false);

        frappe.db.get_doc("Project", frm.doc.custom_project)
            .then(project => {
                const child_sites = project.custom_sites || [];
                frm._project_sites = [...new Set(
                    child_sites.map(row => row.site).filter(Boolean)
                )];
                frm.refresh_field("custom_site");
            })
            .catch(() => {
                frappe.show_alert({
                    message: __("Failed to load sites for the selected project."),
                    indicator: "red"
                });
            });
    },

    // =====================================================
    // QUANTITY FIELD VALIDATION
    // =====================================================
    quantity: function(frm) {
        if (frm.doc.quantity === undefined || frm.doc.quantity === null) return;
        let qty = parseInt(frm.doc.quantity);
        if (isNaN(qty)) {
            frm.set_value("quantity", null);
            return;
        }
        if (qty <= 0) {
            frappe.msgprint(__('Quantity must be greater than 0'));
            frm.set_value("quantity", null);
            return;
        }
        if (qty > 999) {
            frappe.msgprint(__('Quantity cannot exceed 999'));
            frm.set_value("quantity", 999);
        }
    },

    // =====================================================
    // HARD VALIDATION BEFORE SAVE
    // =====================================================
    validate: function(frm) {
        if (frm.doc.quantity !== undefined && frm.doc.quantity !== null) {
            if (frm.doc.quantity <= 0) {
                frappe.throw(__('Quantity must be greater than 0'));
            }
            if (frm.doc.quantity > 999) {
                frappe.throw(__('Quantity cannot exceed 999'));
            }
        }
    },

    // =====================================================
    // ADD EMPLOYEES BUTTON
    // =====================================================
    add_employee_button: function(frm) {
        if (frm.__adding_employees) return;
        frm.__adding_employees = true;

        const job_title = frm.doc.job_title;
        const quantity = frm.doc.quantity;

        if (!job_title) {
            frappe.msgprint(__('Please select a Job Title first'));
            frm.__adding_employees = false;
            return;
        }

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Employee",
                fields: [
                    "name",
                    "employee_name",
                    "custom_iqama_job_title",
                    "first_name",
                    "last_name"
                ],
                filters: {
                    custom_iqama_job_title: job_title
                },
                limit_page_length: quantity && quantity > 0 ? quantity : 0
            },
            freeze: true,
            freeze_message: __("Fetching employees..."),
            callback: function(r) {
                const employees = r.message || [];

                if (!employees.length) {
                    frappe.msgprint(__('No employees found for this Job Title'));
                    frm.__adding_employees = false;
                    return;
                }

                if (frm.doc.employee_table &&
                    frm.doc.employee_table.length === 1 &&
                    !frm.doc.employee_table[0].employee) {
                    frm.clear_table("employee_table");
                }

                const existing = (frm.doc.employee_table || []).map(r => r.employee);
                let added = 0;

                employees.forEach(emp => {
                    if (!existing.includes(emp.name)) {
                        const row = frm.add_child("employee_table");
                        row.employee = emp.name;
                        row.employee_name = emp.employee_name
                            ? emp.employee_name.split(':').pop().trim()
                            : '';
                        row.iqama_job_title = emp.custom_iqama_job_title || '';
                        row.full_name = [emp.first_name, emp.last_name].filter(Boolean).join(' ') || emp.employee_name || '';
                        added++;
                    }
                });

                if (added > 0) {
                    frm.refresh_field("employee_table");
                    frappe.msgprint(__("{0} Employee(s) added successfully", [added]));
                } else {
                    frappe.msgprint(__('No new employees were added'));
                }

                frm.__adding_employees = false;
            },

            error: function() {
                frappe.msgprint(__('Something went wrong'));
                frm.__adding_employees = false;
            }
        });
    }
});

// =====================================================
// CHILD TABLE: Auto-fill Employee Data on manual selection
// =====================================================
frappe.ui.form.on('Employee Project Assignment Detail', 'employee', function(frm, cdt, cdn) {
    const row = locals[cdt][cdn];

    if (!row.employee) {
        row.employee_name = '';
        row.iqama_job_title = '';
        row.full_name = '';
        frm.refresh_field('employee_table');
        return;
    }

    // Fetch all needed fields
    frappe.db.get_value('Employee', row.employee,
        ['employee_name', 'custom_iqama_job_title', 'first_name', 'last_name']
    ).then(r => {
        const emp = r.message;
        if (!emp) return;

        row.employee_name = emp.employee_name
            ? emp.employee_name.split(':').pop().trim()
            : '';

        row.iqama_job_title = emp.custom_iqama_job_title || '';

        // Full name: first_name + last_name, fallback to employee_name
        row.full_name = [emp.first_name, emp.last_name].filter(Boolean).join(' ') || emp.employee_name || '';

        frm.refresh_field('employee_table');
    });
});

frappe.ui.form.on('Project Site', {

    setup(frm) {
        frm.set_query("city", function() {
            if (frm.doc.administrative_region) {
                return {
                    filters: {
                        administrative_region: frm.doc.administrative_region
                    }
                };
            }
        });
    },

    latitude(frm) {
        update_location(frm);
    },

    longitude(frm) {
        update_location(frm);
    }
});

function update_location(frm) {

    if (frm.doc.latitude && frm.doc.longitude) {

        let geojson = {
            "type": "Point",
            "coordinates": [
                parseFloat(frm.doc.longitude), 
                parseFloat(frm.doc.latitude)
            ]
        };

        frm.doc.site_location = JSON.stringify(geojson);
        frm.refresh_field("site_location");
    }
}
